<?php
namespace App\Http\Controllers\ValidasiAhli;
use App\Http\Controllers\Controller;use App\Http\Requests\ValidasiAhli\StoreAssessmentDraftRequest;use App\Models\{ExpertValidationAssessment,ExpertValidationInstrument};use App\Services\Audit\AuditLogger;use App\Services\ValidasiAhli\ExpertValidationService;use Illuminate\Http\Request;
class ExpertValidationController extends Controller { public function adminInstruments(){ return view('pages.validasi-ahli.admin-instruments',['items'=>ExpertValidationInstrument::query()->latest()->get()]); } public function adminStoreInstrument(Request $request, AuditLogger $audit){ $v=$request->validate(['code'=>'required|string|max:50|unique:expert_validation_instruments,code','title'=>'required|string|max:150','description'=>'nullable|string','validator_type'=>'required|in:ahli_sistem_informasi,ahli_visualisasi_data,ahli_keamanan_data','status'=>'required|in:draft,active,closed']); $obj=ExpertValidationInstrument::query()->create($v+['created_by'=>$request->user()->id]); $audit->log('expert.instrument.create',$request,'expert_validation_instruments',$obj->id,[],$obj->toArray()); return back()->with('status','Instrumen tersimpan'); } public function adminInvite(Request $request, ExpertValidationInstrument $instrument, ExpertValidationService $svc, AuditLogger $audit){ $v=$request->validate(['validator_user_id'=>'nullable|integer|exists:users,id','days_valid'=>'required|integer|min:1|max:30']); $token=bin2hex(random_bytes(16)); $inv=$svc->createInvitation($instrument,$v['validator_user_id'] ?? null,$token,now()->addDays($v['days_valid'])); $audit->log('expert.invitation.create',$request,'expert_validation_invitations',$inv->id,[],['expires_at'=>$inv->expires_at]); return back()->with('status','Undangan validator dibuat: '.$token); } public function validatorList(Request $request){ $items=ExpertValidationInstrument::query()->where('status','active')->get(); return view('pages.validasi-ahli.validator-list',compact('items')); } public function validatorOpen(Request $request, ExpertValidationInstrument $instrument, AuditLogger $audit){ $audit->log('expert.validation.artifact.view',$request,'expert_validation_instruments',$instrument->id); $assessment=ExpertValidationAssessment::query()->firstOrCreate(['instrument_id'=>$instrument->id,'validator_user_id'=>$request->user()->id],['status'=>'draft']); return view('pages.validasi-ahli.validator-form',compact('instrument','assessment')); } public function saveDraft(StoreAssessmentDraftRequest $request, ExpertValidationInstrument $instrument, ExpertValidationService $svc, AuditLogger $audit){ $assessment=$svc->saveDraft($instrument,$request->user()->id,$request->validated()); $audit->log('expert.validation.draft.save',$request,'expert_validation_assessments',$assessment->id); return back()->with('status','Draft validasi tersimpan'); } public function submitFinal(Request $request, ExpertValidationInstrument $instrument, ExpertValidationService $svc, AuditLogger $audit){ $assessment=$svc->submitFinal($instrument,$request->user()->id,$audit,$request); return redirect()->route('expert.validator.list')->with('status','Submit final berhasil, hasil terkunci.'); } public function recap(Request $request, ExpertValidationService $svc, AuditLogger $audit){ $data=$svc->recap(); $audit->log('expert.validation.recap.view',$request,'expert_validation_assessments'); return view('pages.validasi-ahli.recap',compact('data')); }}

